srcDoc.css:
body {
  font-family: sans-serif;
  margin: 0;
  padding: 10px;
}

.grid-vitrina {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(220px, 1fr));
  gap: 16px;
}

.tarjeta {
  background: #fff;
  border: 1px solid #e5e7eb;
  border-radius: 8px;
  padding: 16px;
  text-align: center;
  box-shadow: 0 4px 6px -1px rgba(0, 0, 0, 0.1);
  transition: transform 0.2s;
}

.tarjeta:hover {
  transform: translateY(-3px);
}

.img-nave {
  width: 100%;
  height: 120px;
  object-fit: contain;
  margin-bottom: 12px;
}

.nombre {
  font-weight: bold;
  font-size: 16px;
  margin-bottom: 8px;
  color: #111827;
}

.precio {
  font-size: 14px;
  color: #4b5563;
  margin-bottom: 4px;
}

.stock {
  font-size: 14px;
  font-weight: bold;
  margin-bottom: 16px;
  color: #22c55e;
}

.stock-cero {
  color: #ef4444;
}

.btn-comprar {
  width: 100%;
  padding: 10px;
  background: #c084fc;
  border: none;
  border-radius: 6px;
  color: white;
  font-weight: bold;
  cursor: pointer;
}

.btn-comprar:hover {
  background: #a855f7;
}

.btn-comprar:disabled {
  background: #d1d5db;
  cursor: not-allowed;
}

