function construirVitrina(model) {
  // 1. ESCUDO TRY-CATCH TOTAL
  try {
    const radar = document.getElementById('radar');
    const grid = document.querySelector('.grid-vitrina');
    if (!radar || !grid) return;

    // --- EXTRACCIÓN DE DICCIONARIO DESDE EL MODELO ---
    const txt = model.textos || {
      precio: "Precio:",
      stock: "Stock:",
      btn_comprar: "Añadir a la Orden",
      btn_login: "Inicia Sesión",
      agotado: "AGOTADO",
      radar_construyendo: "Construyendo plano holográfico...",
      item_desconocido: "Item Desconocido"
    };
    radar.style.display = 'block';
    radar.innerHTML = `[3] ${txt.radar_construyendo}`;
    grid.innerHTML = '';

    // Verificación de seguridad de datos
    if (!model || !model.productos) {
      radar.innerHTML = "<span style='color:orange'>⚠️ Error: Model.productos missing.</span>";
      return;
    }
    if (!Array.isArray(model.productos)) {
      radar.innerHTML = "<span style='color:red'>❌ Error: 'productos' is not an array.</span>";
      return;
    }
    if (model.productos.length === 0) {
      radar.innerHTML = "<span style='color:blue'>✅ Catálogo vacío / Empty catalog.</span>";
      return;
    }
    const sesionActiva = model.sesion && model.sesion.piloto_id && model.sesion.piloto_id !== "invitado";
    radar.style.display = 'none';
    model.productos.forEach(item => {
      const cantidad = item.stock_total || item.stock || item.cantidad || 0;
      const precioRaw = item.precio_cliente || item.mejor_precio || item.precio_isk || item.precio || 0;
      const precio = Number(precioRaw).toLocaleString('en-US');
      const id = item.item_id || 1;
      const nombre = item.nombre_item || item.nombre || txt.item_desconocido;

      // Lógica de estado del botón traducida
      const estaAgotado = cantidad === 0;
      const botonHabilitado = sesionActiva && !estaAgotado;
      let textoBoton = txt.btn_comprar;
      if (!sesionActiva) textoBoton = txt.btn_login;
      if (estaAgotado) textoBoton = txt.agotado;
      const tarjeta = document.createElement('div');
      tarjeta.className = 'tarjeta';
      tarjeta.innerHTML = `
        <img class="img-nave" src="https://images.evetech.net/types/${id}/icon?size=256" onerror="this.src='https://images.evetech.net/types/34/icon'" alt="${nombre}">
        <div class="nombre">${nombre}</div>
        <div class="precio">${txt.precio} ${precio} ISK</div>
        <div class="${cantidad > 0 ? 'stock' : 'stock stock-cero'}">${cantidad > 0 ? `${txt.stock} ${cantidad} unds.` : txt.agotado}</div>
        <button class="btn-comprar" ${!botonHabilitado ? 'disabled' : ''}>${textoBoton}</button>
      `;
      if (botonHabilitado) {
        tarjeta.querySelector('button').addEventListener('click', () => {
          appsmith.updateModel({
            itemSeleccionado: item
          });
          setTimeout(() => appsmith.triggerEvent('onComprar'), 50);
        });
      }
      grid.appendChild(tarjeta);
    });
  } catch (error) {
    const radar = document.getElementById('radar');
    if (radar) {
      radar.style.display = 'block';
      radar.innerHTML = `<span style='color:#ef4444; font-weight:bold;'>⚠️ Fallo en la Matriz: ${error.message}</span>`;
    }
    console.error("GridFlow Logistics - Error crítico evitado:", error);
  }
}
appsmith.onReady(() => {
  construirVitrina(appsmith.model);
});
appsmith.onModelChange(nuevoModelo => {
  construirVitrina(nuevoModelo);
});

